# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

import android.content.Intent
import android.graphics.Bitmap
import android.net.Uri
import android.os.Bundle
import android.provider.MediaStore
import androidx.appcompat.app.AppCompatActivity
import kotlinx.android.synthetic.main.activity_main.*

class MainActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)
        
        // Check if there is any shared data in the intent
        val intent = intent
        if (Intent.ACTION_SEND.equals(intent.action, ignoreCase = true)) {
            if ("text/plain" == intent.type || "image/*" == intent.type) {
                handleSendText(intent)
            } 
        } 
    }
    
    // Handles text data from shared intents 
    fun handleSendText(intent: Intent) {
        try {
            val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
            if (sharedText != null && sharedText.startsWith("http")) { // Check for URL
                tvURL.text = sharedText
            } else if (sharedText != null) { 
                tvNormalText.text = sharedText 
            } 
        } catch(e: Exception) {
            e.printStackTrace()
        }  
    }
    
    // Handle image from the intent and show in ImageView
    fun handleSendImage(intent: Intent) {
        try {
            val sharedImage = intent.getParcelableExtra<Bitmap>(Intent.EXTRA_STREAM) 
            if (sharedImage != null) {
                ivShareImage.setImageURI(null) // Clear any existing image
                ivShareImage.setImageBitmap(sharedImage)
            } else {
                val imageUrl = intent.dataString
                if (!imageUrl.isNullOrEmpty()) {
                    try {
                        val bitmap: Bitmap? = MediaStore.Images.Media.getBitmap(contentResolver, Uri.parse(imageUrl))
                        ivShareImage?.setImageBitmap(bitmap)
                    } catch (e: IOException) {
                        e.printStackTrace()
                    } 
                }
            } 
        } catch(e: Exception) {
            e.printStackTrace()
        } 
    }
}